.xt-text:nth-of-type(2), .xt-text:nth-of-type(3) { display: inline-block; font-size: 14px; margin-left: 14px;color: #666; margin-bottom: 16px; }
.xt-text:nth-of-type(2)::before { content: ""; display: inline-block; width: 4px; height: 15px; background-color: #d1d1d6; border-radius: 2px; margin-right: 8px; vertical-align: -3px; }
.xt-text:nth-of-type(2)::after { content: " | "; margin: 0 2px; position: relative; top: -1px}
